const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;

const BASE_PRICE_BY_TYPE: Record<string, number> = {
  potion: 40,
  amulet: 60,
  staff: 80,
};

export function quote(input: { customer: { yearsWithMHPCO: number }; items: { type: string }[] }): number {
  if (input.items.length === 0) return PROCESSING_FEE;
  const basePrice = BASE_PRICE_BY_TYPE[input.items[0].type];
  const firstInsuranceSurcharge = basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
  return basePrice + firstInsuranceSurcharge + PROCESSING_FEE;
}
